    "active" => [
        ["algo" => 110, "uuid" => "b6fb58", "name" => "pbkdf2", "type" => "kdf", "status" => "active", "title" => "PBKDF2", "description_md" => "PBKDF2 (Password-Based Key Derivation Function 2) is defined in RFC 8018 and NIST SP 800-132. It stretches a password into a fixed-length key by applying a pseudorandom function (usually HMAC-SHA256) repeatedly over many iterations. The iteration count is the primary security knob: higher iterations = slower brute force. Supports any output length and includes a salt to prevent rainbow table attacks.\n\nUsed in:\n- WPA2/WPA3 Wi-Fi password hashing\n- iOS/macOS keychain encryption\n- PKCS#12 key wrapping\n- Many legacy web authentication systems\n\nMinimum 310,000 iterations recommended with HMAC-SHA256 (OWASP 2023). Low iteration counts are exploitable. Argon2id is the modern replacement for password storage.", "mental_model" => "Password run through a blender 310,000 times with a pinch of salt.", "purpose" => ["password hashing", "key derivation"], "good_for" => ["wpa2 keys", "pkcs12", "legacy auth systems"], "avoid_for" => ["new password storage (use argon2id)", "low iteration counts"], "pros" => ["widely supported", "variable output length", "salt support", "nist approved"], "cons" => ["gpu-parallelizable", "no memory hardness", "needs high iterations"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Grover reduces effective strength; increase iterations.", "post_quantum_status" => 2, "example" => ["scenario" => "WPA2 PSK derivation", "input" => ["password" => "Tr0ub4dor&3", "salt" => "MyHomeNetwork", "iterations" => 4096, "keylen" => 32, "prf" => "hmac-sha256"], "output" => ["key" => "3b4c6a2f1e9d7b5a8f3c2e1d4b7a6f9e2c1b4a7f3e9d2c1b4a7f6e9d3c2b1a4f"]], "flow" => ["password + salt", "hmac-prf iteration loop", "concatenate blocks", "truncate to keylen"], "related" => ["pbkdf2-hmac-sha256", "pbkdf2-hmac-sha512", "argon2id", "bcrypt"]],
        ["algo" => 112, "uuid" => "9a4030", "name" => "pbkdf2-hmac-sha256", "type" => "kdf", "status" => "active", "title" => "PBKDF2-HMAC-SHA256", "description_md" => "PBKDF2-HMAC-SHA256 is PBKDF2 using HMAC-SHA256 as the pseudorandom function. It is the OWASP-recommended PBKDF2 variant with a minimum of 310,000 iterations for password hashing. Each iteration applies HMAC-SHA256 to the previous output, making brute-force expensive on CPUs. Still GPU-parallelizable without memory hardness, which is the primary weakness.\n\nUsed in:\n- Django password hasher (default since 2.0)\n- AWS Cognito password verification\n- OpenSSL key wrapping\n- Many modern web frameworks\n\nAlways use a unique 16+ byte random salt per user. Output is 32 bytes by default but can be extended. For new systems, prefer Argon2id which adds memory hardness. Use this when Argon2 is unavailable or when NIST/FIPS compliance is required.", "mental_model" => "SHA256-powered password stretcher, OWASP approved.", "purpose" => ["password hashing", "key derivation"], "good_for" => ["django auth", "fips environments", "key stretching"], "avoid_for" => ["new password storage without fips constraint"], "pros" => ["nist fips approved", "310k iterations practical", "widely available"], "cons" => ["gpu parallelizable", "no memory hardness"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover weakens SHA256 core; use 600k+ iterations post-quantum.", "post_quantum_status" => 2, "example" => ["scenario" => "Django user password hash", "input" => ["password" => "hunter2!", "salt" => "a3f1c2e4b5d6a7f8", "iterations" => 320000, "keylen" => 32], "output" => ["key" => "7e4f1a2b3c8d5e9f0a1b4c7d2e3f8a5b9c6d1e4f7a2b3c8d5e9f0a1b4c7d2e3f"]], "flow" => ["password + salt", "hmac-sha256 loop x310000", "32-byte output"], "related" => ["pbkdf2", "pbkdf2-hmac-sha512", "argon2id"]],
        ["algo" => 113, "uuid" => "b6b9c9", "name" => "pbkdf2-hmac-sha512", "type" => "kdf", "status" => "active", "title" => "PBKDF2-HMAC-SHA512", "description_md" => "PBKDF2-HMAC-SHA512 uses HMAC-SHA512 as the PRF, producing up to 64-byte output per block. SHA512 is slower on 32-bit hardware (including most GPUs) than SHA256, which gives slightly better brute-force resistance per iteration. OWASP recommends 120,000 iterations with this variant.\n\nUsed in:\n- iOS passcode derivation (Secure Enclave KDF)\n- macOS FileVault disk encryption\n- Some VPN implementations (OpenVPN with SHA512)\n\nThe 64-byte block size makes it attractive for deriving longer keys (e.g., 512-bit encryption keys or split key+IV material) without needing multiple passes. Slower on GPU than PBKDF2-HMAC-SHA256 because SHA512 is less GPU-friendly, but Argon2id is still the recommended upgrade path for password storage.", "mental_model" => "64-byte SHA512 password stretcher, slightly GPU-resistant.", "purpose" => ["password hashing", "long key derivation"], "good_for" => ["ios passcode kdf", "macos filevault", "long key material"], "avoid_for" => ["new systems without legacy constraints"], "pros" => ["64-byte output", "gpu-slower than sha256 variant", "nist approved"], "cons" => ["no memory hardness", "still gpu-attackable"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover halves SHA512 strength; use 250k+ iterations.", "post_quantum_status" => 2, "example" => ["scenario" => "FileVault disk encryption key derivation", "input" => ["password" => "Correct-Horse-Battery-Staple", "salt" => "b9e3f1a2c4d5e6f7a8b9c0d1", "iterations" => 120000, "keylen" => 64], "output" => ["key" => "1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f"]], "flow" => ["password + salt", "hmac-sha512 loop x120000", "64-byte output"], "related" => ["pbkdf2-hmac-sha256", "argon2id", "scrypt"]],
        ["algo" => 114, "uuid" => "5290ca", "name" => "bcrypt", "type" => "kdf", "status" => "active", "title" => "bcrypt", "description_md" => "bcrypt is a password hashing function designed by Niels Provos and David Mazieres in 1999. Based on the Blowfish cipher, it includes a cost factor that controls work per hash. The output is a 60-character string embedding the cost factor, salt, and hash. Blowfish's expensive key setup makes bcrypt naturally resistant to GPU acceleration.\n\nUsed in:\n- PHP `password_hash()` default\n- Ruby on Rails has_secure_password\n- Spring Security default encoder\n- Most web frameworks before Argon2\n\nCost factor 12 is recommended for login flows (2024). bcrypt truncates passwords at 72 bytes; pre-hash with SHA256 if longer inputs are needed. Does not support output lengths beyond 60 characters. Argon2id is preferred for new systems but bcrypt remains the safe, proven choice for most web authentication.", "mental_model" => "Blowfish-powered adaptive password lock with built-in cost dial.", "purpose" => ["password hashing", "authentication"], "good_for" => ["web login", "user auth", "php/ruby/java apps"], "avoid_for" => ["passwords >72 bytes without prehash", "non-password KDF use"], "pros" => ["built-in salt", "adaptive cost", "gpu-resistant", "widely supported"], "cons" => ["72 byte limit", "no memory hardness", "60-char output only"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Cost factor can be raised; no immediate quantum threat.", "post_quantum_status" => 3, "example" => ["scenario" => "PHP user registration password hash", "input" => ["password" => "p@ssw0rd!2024", "cost" => 12], "output" => ["hash" => "$2y$12\$LKJ7sd8fNs3k1aJf3d9Q2.eHq1K9wXpY0mZvN7R3cT4dU8fV6gW5e"]], "flow" => ["salt generation", "blowfish expensive key setup", "64 iterations of encrypt", "60-char output string"], "related" => ["argon2id", "scrypt", "pbkdf2-hmac-sha256"]],
        ["algo" => 115, "uuid" => "2a412b", "name" => "scrypt", "type" => "kdf", "status" => "active", "title" => "scrypt", "description_md" => "scrypt is a memory-hard password KDF designed by Colin Percival (2009). Its N, r, p parameters control CPU, memory, and parallelism costs. Memory hardness makes ASIC and GPU attacks expensive, since attackers must allocate large RAM per attempt.\n\nUsed in:\n- Litecoin proof-of-work\n- SSH key encryption (OpenSSH private key format)\n- macOS Keychain (some variants)\n- libsodium `crypto_pwhash_scryptsalsa208sha256`\n\nRecommended parameters for interactive login: N=32768, r=8, p=1 (uses ~32MB RAM). For sensitive key storage: N=1048576, r=8, p=1 (~1GB RAM). Argon2id is now preferred over scrypt in most new systems because it has clearer parameter guidance and NIST recommendation. scrypt is still strong and widely available.", "mental_model" => "RAM-hungry password hasher that makes ASICs expensive.", "purpose" => ["password hashing", "memory-hard key derivation"], "good_for" => ["ssh key encryption", "litecoin pow", "high-value password protection"], "avoid_for" => ["low-memory environments", "new systems (prefer argon2id)"], "pros" => ["memory hard", "gpu/asic resistant", "widely available"], "cons" => ["complex parameter tuning", "high memory use", "argon2id preferred"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Memory hardness limits quantum speedup significantly.", "post_quantum_status" => 3, "example" => ["scenario" => "OpenSSH private key encryption", "input" => ["password" => "my-ssh-key-passphrase", "salt" => "c3f1a2b4e5d6f7a8b9c0d1e2", "N" => 32768, "r" => 8, "p" => 1, "keylen" => 32], "output" => ["key" => "4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5"]], "flow" => ["pbkdf2 init", "blockmix with salsa20/8", "romix memory fill", "pbkdf2 finalize"], "related" => ["argon2id", "bcrypt", "pbkdf2"]],
        ["algo" => 116, "uuid" => "813f8a", "name" => "argon2d", "type" => "kdf", "status" => "active", "title" => "Argon2d", "description_md" => "Argon2d is a memory-hard KDF that accesses memory in a data-dependent pattern, maximizing resistance against GPU and ASIC attacks by making the memory access pattern depend on the password itself. Winner of the Password Hashing Competition (PHC) in 2015.\n\nParameters: time cost (t), memory cost (m, in KB), parallelism (p).\n\nArgon2d is optimized for cryptocurrency proof-of-work and systems where side-channel attacks via memory access timing are not a concern. Not recommended for password hashing in interactive user-facing systems because the data-dependent memory access makes it vulnerable to cache-timing side-channel attacks on shared hardware (e.g., web servers). Use Argon2id for general password hashing. Argon2d is best for backend batch operations where side-channels are controlled.", "mental_model" => "RAM-hard hasher with data-dependent memory walk - use for PoW not login.", "purpose" => ["proof-of-work", "memory-hard kdf"], "good_for" => ["cryptocurrency pow", "controlled environments", "batch operations"], "avoid_for" => ["interactive login (use argon2id)", "shared hosting"], "pros" => ["maximum asic resistance", "phc winner", "memory hard"], "cons" => ["side-channel vulnerable", "not safe for interactive auth on shared hardware"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Memory hardness limits quantum speedup.", "post_quantum_status" => 3, "example" => ["scenario" => "Cryptocurrency PoW hash", "input" => ["password" => "block_candidate_nonce_a3f1", "salt" => "e2b3c4d5f6a7b8c9", "time" => 3, "memory" => 65536, "parallelism" => 4], "output" => ["hash" => "\$argon2d\$v=19\$m=65536,t=3,p=4\$e2b3c4d5f6a7b8c9$7f3a1b2c4d5e6f7a8b9c0d1e2f3a4b5c"]], "flow" => ["fill memory matrix", "data-dependent pass", "final block extract", "encode output"], "related" => ["argon2i", "argon2id", "scrypt"]],
        ["algo" => 117, "uuid" => "f57618", "name" => "argon2i", "type" => "kdf", "status" => "active", "title" => "Argon2i", "description_md" => "Argon2i is a memory-hard KDF that accesses memory in a data-independent pattern. This makes it safe against side-channel attacks that observe memory access timing, at the cost of slightly weaker ASIC resistance compared to Argon2d.\n\nBest suited for:\n- Key derivation from passwords in shared environments\n- Situations where side-channel attacks via cache timing are a real threat\n- Cryptographic key derivation (not just password storage)\n\nArgon2i is also PHC winner (2015). For pure password storage, Argon2id (which combines both) is the recommended default. Argon2i shines when deriving encryption keys from passwords on shared infrastructure where an attacker might observe cache behavior. Use t >= 3 iterations to resist time-memory trade-off attacks.", "mental_model" => "Side-channel-safe RAM hasher for key derivation on shared servers.", "purpose" => ["password-based key derivation", "side-channel resistant"], "good_for" => ["encryption key derivation", "shared hosting environments", "cache-timing safe auth"], "avoid_for" => ["pure password storage (prefer argon2id)"], "pros" => ["side-channel safe", "phc winner", "memory hard"], "cons" => ["weaker asic resistance than argon2d", "argon2id preferred for storage"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Memory hardness limits quantum attack benefit.", "post_quantum_status" => 3, "example" => ["scenario" => "Derive AES-256 key from user passphrase on shared server", "input" => ["password" => "vault-unlock-passphrase-2024", "salt" => "f1a2b3c4d5e6f7a8", "time" => 3, "memory" => 65536, "parallelism" => 2, "keylen" => 32], "output" => ["key" => "\$argon2i\$v=19\$m=65536,t=3,p=2\$f1a2b3c4d5e6f7a8$3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f"]], "flow" => ["fill memory (data-independent)", "independent pass", "final block", "key output"], "related" => ["argon2d", "argon2id", "scrypt"]],
        ["algo" => 118, "uuid" => "7d8922", "name" => "argon2id", "type" => "kdf", "status" => "active", "title" => "Argon2id", "description_md" => "Argon2id is the recommended hybrid variant of Argon2 (PHC winner, 2015). It combines Argon2i's first pass (data-independent, side-channel safe) with Argon2d's subsequent passes (data-dependent, ASIC resistant). This gives the best of both worlds: protection against side-channel attacks AND strong ASIC/GPU resistance.\n\nOWASP recommends Argon2id as the **first choice** for password hashing:\n- m=19456 KB (19 MB), t=2, p=1 for low-memory environments\n- m=65536 KB (64 MB), t=3, p=4 for high-security systems\n\nUsed in:\n- 1Password, Bitwarden vault encryption\n- Signal Protocol key derivation\n- libsodium `crypto_pwhash` default\n- Rust `argon2` crate default\n\nAlways generate a unique 16-byte random salt per credential.", "mental_model" => "Best-in-class password hasher: ASIC-resistant + side-channel safe.", "purpose" => ["password hashing", "key derivation"], "good_for" => ["user login", "vault encryption", "credential storage"], "avoid_for" => ["none; this is the recommended default"], "pros" => ["owasp #1 recommendation", "side-channel safe", "asic resistant", "memory hard", "nist approved"], "cons" => ["higher memory use than bcrypt"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Memory hardness significantly limits quantum speedup.", "post_quantum_status" => 4, "example" => ["scenario" => "Bitwarden vault master password hash", "input" => ["password" => "correct-horse-battery-staple!", "salt" => "user@example.com", "time" => 3, "memory" => 65536, "parallelism" => 4], "output" => ["hash" => "\$argon2id\$v=19\$m=65536,t=3,p=4\$dXNlckBleGFtcGxlLmNvbQ$8a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9"]], "flow" => ["argon2i first pass (data-independent)", "argon2d subsequent passes", "final block extraction", "encoded output"], "related" => ["argon2d", "argon2i", "scrypt", "bcrypt"]],
        ["algo" => 119, "uuid" => "77eec4", "name" => "yescrypt", "type" => "kdf", "status" => "active", "title" => "yescrypt", "description_md" => "yescrypt is an advanced memory-hard KDF and password hashing scheme designed by Alexander Peslyak (Solar Designer). It extends scrypt with additional features: ROM (read-only memory) for client puzzles, SIMD optimizations, and a wider parameter space. Designed to be computationally expensive for both CPUs and ASICs.\n\nUsed in:\n- Linux `/etc/shadow` default since Fedora 35 / Debian 11\n- libxcrypt (replaces glibc crypt on modern Linux)\n- System authentication on modern Linux distributions\n\nyescrypt is the default on most modern Linux systems where you see `\$y$` in shadow password entries. It outperforms bcrypt and scrypt in security-per-memory and provides ROM-hardening. For web applications, Argon2id is generally more portable. yescrypt is best for OS-level authentication.", "mental_model" => "Modern Linux shadow password default, scrypt on steroids.", "purpose" => ["os password hashing", "memory-hard kdf"], "good_for" => ["linux system auth", "shadow passwords", "high-security local accounts"], "avoid_for" => ["web apps without libxcrypt", "cross-platform portability needs"], "pros" => ["linux default", "rom hardening", "simd optimized", "strong asic resistance"], "cons" => ["less portable than argon2id", "complex parameters"], "difficulty" => 2, "security" => 5, "quantum_impact" => "ROM hardening and memory cost limit quantum speedup.", "post_quantum_status" => 4, "example" => ["scenario" => "Linux system account password hash (Fedora 38)", "input" => ["password" => "S3cur3LinuxP@ss", "params" => "j75", "salt" => "Qm4K2fD8nR9pL1xW"], "output" => ["hash" => "\$y\$j75\$Qm4K2fD8nR9pL1xW$3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0"]], "flow" => ["yescrypt init", "rom phase", "blockmix passes", "finalize hash string"], "related" => ["scrypt", "argon2id", "sha512crypt"]],
        ["algo" => 120, "uuid" => "a08444", "name" => "lyra2", "type" => "kdf", "status" => "active", "title" => "Lyra2", "description_md" => "Lyra2 is a memory-hard KDF and password hashing scheme designed by Marcos Simplicio et al. (Brazil). PHC runner-up. Uses a sponge-based construction (based on Blake2 or BlaMka) with a tunable memory matrix. Key feature: sequential memory-hard with a visiting phase for additional strength.\n\nUsed in:\n- Vertcoin cryptocurrency (Lyra2RE, Lyra2REv2)\n- Brazilian national cryptographic standards proposals\n- libsodium research builds\n\nLyra2 supports very fine-grained parameter tuning: time, memory columns, rows, and parallelism. The sponge construction gives it good theoretical foundations. Less widely deployed than Argon2id for web apps but strong in cryptocurrency PoW contexts. Lyra2REv3 is the current Vertcoin PoW algorithm. For general password hashing, Argon2id is more battle-tested.", "mental_model" => "Sponge-based Brazilian PHC runner-up, popular in PoW coins.", "purpose" => ["password hashing", "proof-of-work kdf"], "good_for" => ["vertcoin pow", "cryptocurrency", "research"], "avoid_for" => ["general web auth (use argon2id)"], "pros" => ["fine-grained tuning", "sponge construction", "phc runner-up", "memory hard"], "cons" => ["less battle-tested than argon2id", "complex params"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Memory hardness limits quantum attack benefit.", "post_quantum_status" => 3, "example" => ["scenario" => "Vertcoin PoW hash input", "input" => ["block_header" => "0000000a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e", "time" => 1, "memory" => 4096, "cols" => 8, "rows" => 8], "output" => ["lyra2_hash" => "2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3"]], "flow" => ["bootstrap with sponge", "fill memory matrix", "visiting phase", "squeeze output"], "related" => ["scrypt", "argon2id", "yescrypt"]],
        ["algo" => 122, "uuid" => "85463d", "name" => "balloon", "type" => "kdf", "status" => "active", "title" => "Balloon Hashing", "description_md" => "Balloon Hashing is a memory-hard KDF with provable security guarantees designed by Boneh, Corrigan-Gibbs, and Schechter (Stanford, 2016). Unique among password KDFs for having a formal security proof of memory hardness in the random oracle model.\n\nParameters: time cost (t), memory space cost (s), delta (mixing degree, usually 3).\n\nUsed in:\n- Google Titan Security Key firmware\n- Chrome password hashing (Chromium project)\n- Academic reference implementations\n\nBalloon provides a clean construction with fewer moving parts than scrypt or Argon2. The proof of security makes it attractive for formal verification contexts. Not yet as widely deployed as Argon2id or scrypt but gaining adoption in Google infrastructure. The three-phase design (expand, mix, extract) is straightforward to audit.", "mental_model" => "Provably memory-hard Stanford password hasher used by Google.", "purpose" => ["password hashing", "memory-hard kdf"], "good_for" => ["google titan", "formal verification needs", "research-grade systems"], "avoid_for" => ["production web auth without library support"], "pros" => ["provable memory hardness", "simple construction", "google backed"], "cons" => ["less library support than argon2id", "newer deployment history"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Proven memory hardness limits quantum speedup.", "post_quantum_status" => 4, "example" => ["scenario" => "Chrome password hash", "input" => ["password" => "myGooglePass#2024", "salt" => "d4e5f6a7b8c9d0e1", "s_cost" => 1024, "t_cost" => 3, "delta" => 3], "output" => ["hash" => "5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6"]], "flow" => ["expand: fill buffer with hash", "mix: delta random reads+writes", "extract: final block output"], "related" => ["argon2id", "scrypt", "yescrypt"]],
    ],
    "legacy" => [
        ["algo" => 111, "uuid" => "cadcd9", "name" => "pbkdf2-hmac-sha1", "type" => "kdf", "status" => "legacy", "title" => "PBKDF2-HMAC-SHA1", "description_md" => "PBKDF2-HMAC-SHA1 is PBKDF2 using HMAC-SHA1 as the PRF. It was the original PBKDF2 variant specified in RFC 2898 and is still widely found in legacy systems. SHA1's weaknesses (collision attacks) do not directly compromise PBKDF2's key derivation security because PBKDF2 relies on HMAC's preimage resistance, not collision resistance. However, SHA1 is slower than SHA256 per iteration, making it a poor choice for high iteration counts.\n\nFound in:\n- WPA/WPA2 passphrase derivation (legacy APs)\n- iOS keychain legacy entries\n- OpenSSL legacy PEM encryption\n- Many older Java KeyStore (JKS) implementations\n\nSHA1 is deprecated for new use. Migrate to PBKDF2-HMAC-SHA256 or Argon2id. OWASP recommends 1,300,000+ iterations with SHA1 if forced to use it.", "mental_model" => "The original PBKDF2 with deprecated SHA1 PRF.", "purpose" => ["legacy password hashing", "legacy key derivation"], "good_for" => ["wpa/wpa2 legacy aps", "old ios keychain", "legacy jks"], "avoid_for" => ["new systems", "any new development"], "pros" => ["rfc 2898 original", "widely compatible"], "cons" => ["sha1 deprecated", "slower than sha256 variant", "1.3M iterations needed"], "difficulty" => 1, "security" => 2, "quantum_impact" => "SHA1 weakened by Grover; very high iterations required.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy WPA2 PSK derivation", "input" => ["password" => "HomeWifi2012!", "salt" => "NETGEAR_Legacy", "iterations" => 4096, "keylen" => 32], "output" => ["key" => "1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2"]], "flow" => ["password + salt", "hmac-sha1 loop", "block concat", "truncate"], "related" => ["pbkdf2-hmac-sha256", "pbkdf2", "argon2id"]],
        ["algo" => 121, "uuid" => "663d0d", "name" => "catena", "type" => "kdf", "status" => "legacy", "title" => "Catena", "description_md" => "Catena is a memory-hard KDF framework designed by Forler, Lucks, and Wenzel (Germany, 2013). A PHC finalist with a graph-based memory-hard construction. Catena uses a directed acyclic graph (DAG) structure to fill and traverse memory, providing provable memory hardness. Supports client-independent updates (re-hashing without the original password) and server-relief mode.\n\nCatena-Dragonfly and Catena-Butterfly are the two main variants. Catena was a strong PHC submission but lost to Argon2 due to complexity and fewer available implementations. No practical attacks known. Still cryptographically sound.\n\nNot widely deployed outside research and German academic contexts. Use Argon2id for production. Catena is relevant for understanding advanced memory-hard constructions and for systems requiring server-relief properties.", "mental_model" => "DAG-based memory hard PHC finalist with server-relief support.", "purpose" => ["memory-hard password hashing", "server-relief kdf"], "good_for" => ["research", "server-relief scenarios", "german standards context"], "avoid_for" => ["production systems (prefer argon2id)"], "pros" => ["provable memory hardness", "server-relief mode", "dag construction"], "cons" => ["limited library support", "argon2 preferred", "complex"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Memory hardness provides moderate quantum resistance.", "post_quantum_status" => 2, "example" => ["scenario" => "Research password hash with server-relief", "input" => ["password" => "catena-test-password", "salt" => "a1b2c3d4e5f6a7b8", "garlic" => 14, "lambda" => 2, "variant" => "dragonfly"], "output" => ["hash" => "3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4"]], "flow" => ["phi function", "dag memory fill", "gamma random walk", "output extraction"], "related" => ["argon2id", "balloon", "lyra2"]],
        ["algo" => 123, "uuid" => "25f1a7", "name" => "pomelo", "type" => "kdf", "status" => "legacy", "title" => "Pomelo", "description_md" => "Pomelo is a memory-hard KDF designed by Hongjun Wu for the Password Hashing Competition (2015). Uses a cache-hard and memory-hard construction based on a custom mixing function. Pomelo was a PHC candidate but did not advance to final selection.\n\nKey properties: variable memory cost (1 KB to 256 GB), time cost, and parallelism lane support. Cache-hard design penalizes off-chip memory access. Simple design with few moving parts.\n\nPomelo received limited cryptanalysis compared to finalists. No serious practical attacks found but the design has had less scrutiny than Argon2. Rarely deployed in production. Primarily of interest for understanding alternative PHC approaches. Use Argon2id for any production deployment. Pomelo's cache-hard properties make it theoretically interesting for ASIC resistance research.", "mental_model" => "Cache-hard PHC candidate with simple structure, rarely deployed.", "purpose" => ["memory-hard password hashing"], "good_for" => ["research", "asic resistance study"], "avoid_for" => ["production systems"], "pros" => ["cache hard", "simple design", "wide memory range"], "cons" => ["limited cryptanalysis", "not widely deployed", "argon2 preferred"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Cache hardness provides some quantum resistance.", "post_quantum_status" => 2, "example" => ["scenario" => "PHC research hash", "input" => ["password" => "pomelo-research-2015", "salt" => "b2c3d4e5f6a7b8c9", "memory" => 8192, "time" => 2, "lanes" => 1], "output" => ["hash" => "4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5"]], "flow" => ["state init", "cache-hard fill", "mixing rounds", "output squeeze"], "related" => ["argon2id", "catena", "lyra2"]],
        ["algo" => 124, "uuid" => "71b7a7", "name" => "makwa", "type" => "kdf", "status" => "legacy", "title" => "Makwa", "description_md" => "Makwa is a password hashing scheme designed by Thomas Pornin (2015, PHC). Unique design: based on modular squaring in a large RSA-like modulus, not a symmetric cipher or hash. This makes it the only PHC candidate rooted in number theory hardness.\n\nFeatures: server-relief delegation (a server can do most work without seeing the password), delegation proofs, and modular arithmetic hardness. Not broken. Security relies on the hardness of factoring the modulus.\n\nIn post-quantum context: if large quantum computers exist, Shor's algorithm could factor the modulus, breaking Makwa's security. This is a fundamental design weakness post-quantum. Never widely deployed due to complexity and the availability of simpler alternatives. Use Argon2id for production. Makwa is academically interesting for its RSA-based design and server-relief properties.", "mental_model" => "RSA-modulus-based password hash with server delegation - broken by quantum.", "purpose" => ["server-relief password hashing"], "good_for" => ["research", "server-relief study", "number theory based auth"], "avoid_for" => ["post-quantum systems", "any production use"], "pros" => ["server-relief delegation", "delegation proofs", "unique number theory base"], "cons" => ["quantum broken (shor)", "complex", "rare library support"], "difficulty" => 4, "security" => 2, "quantum_impact" => "Shor's algorithm can factor the modulus; fully broken post-quantum.", "post_quantum_status" => 1, "example" => ["scenario" => "Server-relief password hash prototype", "input" => ["password" => "makwa-test-2015", "modulus_bits" => 2048, "work_factor" => 4096, "salt" => "c3d4e5f6a7b8c9d0"], "output" => ["makwa_hash" => "MKW2048/4096/c3d4e5f6a7b8c9d0/7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8"]], "flow" => ["modular squaring init", "delegation work factor loop", "modular reduction", "base64url output"], "related" => ["argon2id", "catena", "balloon"]],
        ["algo" => 125, "uuid" => "ec8e18", "name" => "bsdicrypt", "type" => "kdf", "status" => "legacy", "title" => "BSDi crypt", "description_md" => "BSDi crypt (also called extended DES crypt) is an improved version of the original Unix DES crypt, developed by BSDi in the early 1990s. It extends the original 8-character password limit to 128 characters and increases the iteration count using a configurable rounds parameter encoded in the hash string (prefix `_`).\n\nFound in:\n- FreeBSD and OpenBSD legacy `/etc/master.passwd` entries\n- Old IRIX, HP-UX authentication databases\n- NetBSD legacy password files\n\nDespite improvements over the original DES crypt, BSDi crypt is still DES-based and thus severely limited: DES is broken, 64-bit block size, and the algorithm is heavily parallelizable by GPUs. Do not use for any new system. Migrate to yescrypt or Argon2id on modern BSDs. Only relevant for compatibility with decades-old authentication databases.", "mental_model" => "Extended DES Unix password hash from early 1990s BSD.", "purpose" => ["legacy os password hashing"], "good_for" => ["freebsd legacy databases", "old unix compatibility"], "avoid_for" => ["any new system", "any security-sensitive use"], "pros" => ["128-char password support", "configurable rounds"], "cons" => ["des-based and broken", "gpu parallelizable", "obsolete"], "difficulty" => 1, "security" => 1, "quantum_impact" => "DES is already broken; quantum is irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "FreeBSD legacy account migration audit", "input" => ["password" => "oldunixpass", "rounds" => 7168, "salt" => "LOVNLk"], "output" => ["hash" => "_7168LOVNLkdMK4Vo5o6"]], "flow" => ["des key setup", "rounds iteration", "64-bit encrypt", "base64 encoded output"], "related" => ["md5crypt", "sha512crypt", "bcrypt"]],
        ["algo" => 126, "uuid" => "0bf8b3", "name" => "md5crypt", "type" => "kdf", "status" => "legacy", "title" => "md5crypt", "description_md" => "md5crypt (`$1$`) was introduced by Poul-Henning Kamp for FreeBSD in 1994. It replaced DES crypt with an MD5-based iterative hash, removing the 8-character password limit and using a random salt. The output hash starts with `$1$` followed by an 8-character salt and 22-character MD5 hash.\n\nOnce widely deployed across Linux distributions and network equipment:\n- Cisco IOS `enable secret type 1` hashes\n- Old Red Hat / CentOS shadow passwords\n- Old Solaris password files\n- pfSense and other FreeBSD-based appliances\n\nmd5crypt is now considered weak. MD5 is fast, GPUs can test billions per second. The fixed iteration count (1000) cannot be increased. Cracking tools (hashcat, john) trivially attack it. Migrate to SHA-512crypt or yescrypt on legacy systems. Never use for new deployments.", "mental_model" => "1994 FreeBSD MD5 password hash, found in Cisco IOS configs.", "purpose" => ["legacy password hashing"], "good_for" => ["reading old cisco ios hashes", "legacy linux migration"], "avoid_for" => ["any new deployment", "any security context"], "pros" => ["no 8-char limit", "random salt", "widespread legacy support"], "cons" => ["md5 is fast", "fixed 1000 iterations", "trivially crackable by gpu"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already trivially broken classically; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Cisco IOS legacy enable secret", "input" => ["password" => "admin123", "salt" => "Hx4e7fKm"], "output" => ["hash" => "$1\$Hx4e7fKm$8J3kP2qR7tV5wX1yZ6nA0."]], "flow" => ["md5 init", "password+salt mixing", "1000 iterations", "$1$ prefixed output"], "related" => ["sha256crypt", "sha512crypt", "bcrypt"]],
        ["algo" => 127, "uuid" => "be1949", "name" => "sha256crypt", "type" => "kdf", "status" => "legacy", "title" => "SHA-256crypt", "description_md" => "SHA-256crypt (`$5$`) is a password hashing scheme designed by Ulrich Drepper for glibc (2007). It replaced md5crypt with SHA-256 as the core hash, supporting configurable rounds (default 5000, range 1000-999999999) and a unique shuffling step to prevent simple password+salt concatenation attacks.\n\nUsed in:\n- RHEL/CentOS 6/7 legacy shadow passwords\n- Solaris 11 legacy password files\n- Some embedded Linux devices\n\nSHA-256crypt is better than md5crypt but has been superseded by SHA-512crypt and yescrypt. Its 32-byte output is smaller than SHA-512crypt's 64 bytes. GPUs can still attack it efficiently because SHA-256 is not memory-hard. Default 5000 rounds is too low for modern hardware. Migrate to SHA-512crypt or yescrypt.", "mental_model" => "Glibc SHA-256 password hash from 2007, RHEL legacy.", "purpose" => ["legacy password hashing"], "good_for" => ["rhel 6/7 legacy compatibility", "old solaris systems"], "avoid_for" => ["new systems", "high-security auth"], "pros" => ["configurable rounds", "better than md5crypt", "no char limit"], "cons" => ["gpu attackable", "not memory hard", "superseded by sha512crypt/yescrypt"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Grover reduces SHA256 security; increase rounds significantly.", "post_quantum_status" => 1, "example" => ["scenario" => "RHEL 7 legacy shadow entry", "input" => ["password" => "RedHatPass2018!", "salt" => "vF3kP2qR", "rounds" => 5000], "output" => ["hash" => "$5\$rounds=5000\$vF3kP2qR\$Kd8mN4pQ7rS2tU5vW8xY1zA3bC6dE9fG0hI2jK4lM6"]], "flow" => ["sha256 init", "password+salt mixing", "complex shuffling", "rounds iteration", "base64 output"], "related" => ["sha512crypt", "md5crypt", "yescrypt"]],
        ["algo" => 128, "uuid" => "793c19", "name" => "sha512crypt", "type" => "kdf", "status" => "legacy", "title" => "SHA-512crypt", "description_md" => "SHA-512crypt (`$6$`) is a password hashing scheme designed by Ulrich Drepper for glibc (2007). Uses SHA-512 with configurable rounds (default 5000) and a complex byte-shuffling step. Output is 86-character base64. Larger 64-byte digest than SHA-256crypt.\n\nLong the default on major Linux distributions:\n- Ubuntu/Debian (pre-22.04 default before yescrypt)\n- RHEL/CentOS 7/8 default shadow hash\n- Still found in many enterprise Linux environments\n\nSHA-512crypt is better than md5crypt and SHA-256crypt but is not memory-hard. Modern GPU clusters crack low-round SHA-512crypt quickly. The default 5000 rounds is dangerously low. Recommended: 500000+ rounds if you cannot migrate. yescrypt is now the preferred replacement on systems running glibc 2.34+. SHA-512 is slower on GPU than SHA-256, giving some protection.", "mental_model" => "Glibc SHA-512 password hash, long-time Linux default, superseded by yescrypt.", "purpose" => ["password hashing", "linux system auth"], "good_for" => ["rhel/centos 7-8 systems", "debian/ubuntu pre-22.04 legacy"], "avoid_for" => ["new deployments (use yescrypt or argon2id)"], "pros" => ["widely available", "64-byte digest", "configurable rounds", "glibc standard"], "cons" => ["not memory hard", "gpu attackable", "default rounds too low"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Grover reduces SHA512 security; use 500k+ rounds.", "post_quantum_status" => 1, "example" => ["scenario" => "Ubuntu 20.04 user account shadow entry", "input" => ["password" => "Ubuntu@Server2022", "salt" => "nR7kP4qS", "rounds" => 5000], "output" => ["hash" => "$6\$rounds=5000\$nR7kP4qS\$mT9vW2xY5zA8bC1dE4fG7hI0jK3lM6nO9pQ2rS5tU8vW1xY4zA7bC0dE3fG6hI9"]], "flow" => ["sha512 init", "password+salt complex mixing", "byte shuffle step", "rounds iteration", "base64 output"], "related" => ["sha256crypt", "yescrypt", "bcrypt"]],
    ],
    "new" => [
        ["algo" => 129, "uuid" => "e946bb", "name" => "pbkdf1", "type" => "kdf", "status" => "new", "title" => "PBKDF1", "description_md" => "PBKDF1 is the original password-based key derivation function defined in PKCS#5 v1.5 (RFC 2898 Section 5.1). It derives a key by iteratively applying a hash function (MD5, SHA1, or MD2) to a password and salt concatenation. Output is limited to the hash output length: 16 bytes for MD5, 20 bytes for SHA1.\n\nThe output length restriction makes PBKDF1 unsuitable for deriving longer keys. It also lacks the block chaining of PBKDF2, making it weaker. PBKDF1 was already considered obsolete when PBKDF2 was standardized.\n\nFound only in:\n- Very old PKCS#12 files (pre-2000)\n- Ancient SSL/TLS implementations\n- Legacy Java JCE code using `PBEWithMD5AndDES`\n\nDo not use PBKDF1 for any new implementation. PBKDF2 or Argon2id should be used instead. Only relevant for reading very old encrypted archives or legacy JCE compatibility.", "mental_model" => "Obsolete PKCS#5 v1.5 KDF, output limited to one hash length.", "purpose" => ["legacy key derivation"], "good_for" => ["reading old pkcs12 files", "legacy jce compatibility"], "avoid_for" => ["any new development", "any security context"], "pros" => ["simple", "rfc defined"], "cons" => ["output limited to hash size", "weak", "obsolete since pbkdf2"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already weak classically; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Reading legacy JCE PBEWithMD5AndDES archive", "input" => ["password" => "oldlegacypass", "salt" => "a1b2c3d4e5f6a7b8", "iterations" => 1000, "hash" => "sha1"], "output" => ["key" => "3f4a5b6c7d8e9f0a1b2c3d4e"]], "flow" => ["hash(password || salt)", "iterate x1000", "truncate to keylen (max 20B)"], "related" => ["pbkdf2", "pkcs12-kdf", "evp-bytestokey"]],
        ["algo" => 130, "uuid" => "6db5e9", "name" => "pkcs12-kdf", "type" => "kdf", "status" => "new", "title" => "PKCS#12 KDF", "description_md" => "PKCS#12 KDF is the key derivation function defined in RFC 7292 Appendix B, used for deriving keys and IVs from passwords within PKCS#12 files (`.p12`, `.pfx`). It uses a SHA-family hash (SHA1, SHA256, SHA512) with a diversifier byte to produce keys, IVs, or MAC keys from the same password.\n\nUsed exclusively inside PKCS#12 file encryption:\n- Browser certificate import/export\n- Java KeyStore (JKS to P12 migration)\n- OpenSSL `pkcs12` command\n- Windows certificate MMC snap-in\n\nPKCS#12 KDF with SHA1 is the legacy default (still widely encountered). SHA256/SHA512 variants exist but many implementations default to SHA1 for backwards compatibility. Not designed as a strong password KDF; iteration counts are typically very low (e.g., 2048). Do not extract and reuse; this is internal to PKCS#12 only.", "mental_model" => "Internal KDF for PKCS#12 certificate files, not standalone.", "purpose" => ["pkcs12 key/iv derivation"], "good_for" => ["parsing p12/pfx files", "certificate migration"], "avoid_for" => ["standalone password hashing", "any use outside pkcs12"], "pros" => ["rfc standardized", "supports key/iv/mac derivation modes", "sha256/512 variants"], "cons" => ["not designed for password storage", "low iterations typical", "sha1 default legacy"], "difficulty" => 2, "security" => 2, "quantum_impact" => "SHA1 base weakened by Grover; use SHA256 variant.", "post_quantum_status" => 1, "example" => ["scenario" => "PKCS#12 certificate export key derivation", "input" => ["password" => "P12ExportPass!23", "salt" => "b3c4d5e6f7a8b9c0", "iterations" => 2048, "hash" => "sha256", "diversifier" => 1, "keylen" => 32], "output" => ["derived_key" => "6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7"]], "flow" => ["diversifier byte setup", "hash(diversifier || salt || password)", "iterate and concatenate", "truncate to keylen"], "related" => ["pbkdf1", "pbkdf2", "pkcs12"]],
        ["algo" => 131, "uuid" => "04ae94", "name" => "evp-bytestokey", "type" => "kdf", "status" => "new", "title" => "EVP_BytesToKey", "description_md" => "EVP_BytesToKey is OpenSSL's legacy KDF used to derive a key and IV from a password and salt for symmetric encryption. It repeatedly applies MD5 (or another digest) to the password, salt, and previous output until enough bytes are produced. The `openssl enc` command uses this by default.\n\nFound extensively in:\n- Files encrypted with `openssl enc -aes-256-cbc -pass pass:...`\n- Legacy PEM private key encryption (`Proc-Type: 4,ENCRYPTED`)\n- Older node.js crypto operations using `crypto.createCipher()`\n- Python `PyCrypto` legacy encrypted storage\n\nEVP_BytesToKey is not a proper password KDF: it uses a single MD5 iteration with no configurable rounds, making it trivially brute-forceable. OWASP and OpenSSL itself warn against it. When decrypting legacy files you must support it. For new code, use `openssl enc -pbkdf2` or a proper KDF.", "mental_model" => "OpenSSL's legacy MD5-based KDF behind `openssl enc`, do not use for new code.", "purpose" => ["legacy openssl key derivation"], "good_for" => ["decrypting old openssl enc files", "legacy pem key parsing"], "avoid_for" => ["any new encryption", "password storage"], "pros" => ["openssl built-in", "simple", "handles key+iv in one call"], "cons" => ["md5 single iteration", "no memory hardness", "trivially brute-forceable"], "difficulty" => 1, "security" => 1, "quantum_impact" => "MD5 already broken; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Decrypt legacy openssl enc AES-256-CBC file", "input" => ["password" => "oldvaultpass", "salt" => "a1b2c3d4e5f6a7b8", "digest" => "md5", "keylen" => 32, "ivlen" => 16], "output" => ["key" => "3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f", "iv" => "9a0b1c2d3e4f5a6b"]], "flow" => ["D0 = md5(password + salt)", "Di = md5(D(i-1) + password + salt)", "concat Di until keylen+ivlen", "split key and iv"], "related" => ["pbkdf2", "pkcs12-kdf", "aes-cbc"]],
        ["algo" => 132, "uuid" => "6339a5", "name" => "kdf2", "type" => "kdf", "status" => "new", "title" => "KDF2", "description_md" => "KDF2 (Key Derivation Function 2) is defined in ISO 18033-2 and ANSI X9.44. It is a hash-based KDF designed for deriving symmetric keys from shared secrets (e.g., after ECDH key agreement). Not a password KDF; it expects a high-entropy input like a Diffie-Hellman shared secret.\n\nKDF2 works by hashing the input keying material concatenated with a counter and optional shared information: `Hash(Z || Counter || OtherInfo)`. SHA-256 is the typical hash choice. Produces arbitrary-length output.\n\nUsed in:\n- IEEE P1363 key agreement schemes\n- ECIES (Elliptic Curve Integrated Encryption Scheme)\n- Some smart card implementations\n- Legacy financial cryptography systems\n\nKDF2 is simpler than HKDF but lacks the extract-then-expand separation that HKDF provides. For new systems, use HKDF (RFC 5869). KDF2 is primarily encountered in IEEE P1363 and smart card environments.", "mental_model" => "ISO/IEEE KDF for post-ECDH key derivation, simpler but less flexible than HKDF.", "purpose" => ["post-ecdh key derivation", "key agreement kdf"], "good_for" => ["ieee p1363 compliance", "ecies", "smart card systems"], "avoid_for" => ["password-based derivation", "new systems (prefer hkdf)"], "pros" => ["iso standardized", "simple counter mode", "arbitrary output length"], "cons" => ["no extract step", "hkdf preferred", "limited adoption"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Security depends on underlying hash; use SHA256+.", "post_quantum_status" => 2, "example" => ["scenario" => "ECIES shared secret key derivation", "input" => ["shared_secret_Z" => "4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b", "other_info" => "ECIES-AES256-SHA256", "hash" => "sha256", "keylen" => 32], "output" => ["derived_key" => "7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d"]], "flow" => ["Z || counter || OtherInfo", "hash each block", "concatenate outputs", "truncate to keylen"], "related" => ["hkdf", "x963-kdf", "ecdh-kdf", "ecies"]],
    ]
];
?>